3860→void Element::AfterSetAttr(int32_t aNamespaceID, nsAtom* aName,
  3861→                           const nsAttrValue* aValue,
  3862→                           const nsAttrValue* aOldValue,
  3863→                           nsIPrincipal* aMaybeScriptedPrincipal,
  3864→                           bool aNotify) {
  3865→  if (aNamespaceID == kNameSpaceID_None) {
  3866→    if (aName == nsGkAtoms::part) {
  3867→      bool isPart = !!aValue;
  3868→      if (HasPartAttribute() != isPart) {
  3869→        SetHasPartAttribute(isPart);
  3870→        if (ShadowRoot* shadow = GetContainingShadow()) {
  3871→          if (isPart) {
  3872→            shadow->PartAdded(*this);
  3873→          } else {
  3874→            shadow->PartRemoved(*this);
  3875→          }
  3876→        }
  3877→      }
  3878→      MOZ_ASSERT(HasPartAttribute() == isPart);
  3879→    } else if (aName == nsGkAtoms::slot && GetParent()) {
  3880→      if (ShadowRoot* shadow = GetParent()->GetShadowRoot()) {
  3881→        shadow->MaybeReassignContent(*this);
  3882→      }
  3883→    } else if (aName == nsGkAtoms::aria_activedescendant) {
  3884→      ClearExplicitlySetAttrElement(aName);
  3885→      IDREFAttributeValueChanged(aName, aValue);
  3886→    } else if (aName == nsGkAtoms::aria_controls ||
  3887→               aName == nsGkAtoms::aria_describedby ||
  3888→               aName == nsGkAtoms::aria_details ||
  3889→               aName == nsGkAtoms::aria_errormessage ||
  3890→               aName == nsGkAtoms::aria_flowto ||
  3891→               aName == nsGkAtoms::aria_labelledby ||
  3892→               aName == nsGkAtoms::aria_owns) {
